    constexpr Bidir_Range(Container &c)
        : m_begin(c.begin())
        , m_end(c.end()) {
    }

    constexpr bool empty() const noexcept { return m_begin == m_end; }

    constexpr void pop_front() {
      if (empty()) {
        throw std::range_error("Range empty");
      }
      ++m_begin;
    }

    constexpr void pop_back() {
      if (empty()) {
        throw std::range_error("Range empty");
      }
      --m_end;
    }

